const raw = $input.first().json.output;

let contractData;

try {
  const cleaned = raw.replace(/```json|```/g, "").trim();
  contractData = JSON.parse(cleaned);
} catch (error) {
  throw new Error("Failed to parse contract LLM JSON: " + error.message);
}

return {
  json: {
    contract_data: contractData,
    document_id: $('Get Pending Contracts').item.json.id,
    user_id: $('Get Pending Contracts').item.json.user_id
  }
};

const raw = $input.first().json.output;
const contractInfo = $('Parse Contract Response').item.json;

let riskAnalysis;

try {
  const cleaned = raw.replace(/```json|```/g, "").trim();
  riskAnalysis = JSON.parse(cleaned);
} catch (error) {
  // Safe fallback if risk LLM fails
  riskAnalysis = {
    risk_score: 60,
    overall_assessment: 'medium_risk',
    red_flags: [],
    missing_clauses: [],
    favorable_terms: [],
    unfavorable_terms: [],
    compliance_concerns: [],
    recommendations: [],
    status: 'needs_review'
  };
}

// Validate risk score range
if (riskAnalysis.risk_score < 0 || riskAnalysis.risk_score > 100) {
  riskAnalysis.risk_score = Math.max(0, Math.min(100, riskAnalysis.risk_score));
}

return {
  json: {
    contract_data: contractInfo.contract_data,
    risk_analysis: riskAnalysis,
    document_id: contractInfo.document_id,
    user_id: contractInfo.user_id
  }
};

const contract = $input.item.json.contract_data || {};
const risk = $input.item.json.risk_analysis || {};
const document_id = $input.item.json.document_id;
const user_id = $input.item.json.user_id;

// Helper: filter placeholder names
const isValid = (v) => v && String(v).trim() !== '' && !/^_+$/.test(String(v).trim());

// Helper: safe date - returns YYYY-MM-DD or null
const safeDate = (d) => {
  if (!d || d === 'null') return null;
  const parsed = new Date(d);
  return isNaN(parsed.getTime()) ? null : parsed.toISOString().split('T')[0];
};

// Clean parties
const parties = (contract.parties || []).filter(p => isValid(p.name));

// Clean obligations
const key_obligations = (contract.obligations || []).filter(o => isValid(o.party));

// Clean red flags - remove fallback error entries
const red_flags = (risk.red_flags || []).filter(f =>
  !(f.clause_reference === 'N/A' && f.description === 'Risk analysis failed - manual review required')
);

// Risk values
const risk_score = risk.risk_score ?? null;
const requires_legal_review = (risk_score !== null && risk_score > 70) ||
  red_flags.some(f => f.severity === 'critical');

// Confidence score
let confidence_score = 80;
if (risk_score < 30 && red_flags.length === 0) confidence_score = 95;
else if (risk_score > 70 || red_flags.length > 3) confidence_score = 60;
else if (risk_score < 50 && red_flags.length <= 2) confidence_score = 85;

// Validation status
let status = 'needs_review';
if (risk_score > 75 || red_flags.some(f => f.severity === 'critical')) status = 'requires_legal_counsel';
else if (risk_score !== null && risk_score < 30 && red_flags.length === 0) status = 'valid';

return {
  json: {
    document_id,
    user_id,
    contract_data: contract,
    risk_analysis: risk,
    // Flattened for easy access in webhook + DB nodes
    contract_title: contract.contract_title || null,
    contract_type: contract.contract_type || null,
    contract_value: (contract.contract_value > 0) ? contract.contract_value : null,
    currency: contract.currency || 'USD',
    effective_date: safeDate(contract.effective_date),
    expiration_date: safeDate(contract.expiration_date),
    auto_renewal: contract.auto_renewal || false,
    risk_score,
    requires_legal_review,
    governing_law: contract.key_terms?.jurisdiction || null,
    summary: risk.overall_assessment || null,
    parties,
    payment_terms: contract.payment_terms || [],
    key_obligations,
    termination_clauses: contract.key_terms?.termination_clause
      ? [{ description: contract.key_terms.termination_clause }]
      : [],
    red_flags,
    special_conditions: risk.compliance_concerns || [],
    validation: {
      confidence_score,
      status,
      errors: red_flags.filter(f => f.severity === 'critical').map(f => f.description),
      warnings: red_flags.filter(f => f.severity !== 'critical').map(f => f.description)
    }
  }
};
